# Hierarchical compaction: maintain two levels of summary.
# L1 (recent):  abstractive summary of the last 10 turns (~100 tokens)
# L2 (session): rolling merge of all L1 summaries (~200 tokens)
# This bounds total compaction overhead at O(L1 + L2) regardless of length.

from openai import OpenAI
import tiktoken

client = OpenAI(api_key="...")
enc = tiktoken.encoding_for_model("gpt-4o-mini")

def summarise_block(turns: list[dict], max_tokens: int = 120) -> str:
    transcript = "\n".join(f"{m['role'].upper()}: {m['content']}" for m in turns)
    resp = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[{
            "role": "user",
            "content": (
                "Summarise this in one dense paragraph, preserving names, "
                f"decisions, and constraints:\n{transcript}"
            ),
        }],
        max_tokens=max_tokens, temperature=0,
    )
    return resp.choices[0].message.content.strip()

def merge_summaries(s1: str, s2: str, max_tokens: int = 220) -> str:
    resp = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[{
            "role": "user",
            "content": (
                "Merge these two summaries into one dense paragraph:\n\n"
                f"A: {s1}\n\nB: {s2}"
            ),
        }],
        max_tokens=max_tokens, temperature=0,
    )
    return resp.choices[0].message.content.strip()

class HierarchicalCompactor:
    L1_TRIGGER = 10   # L1 compaction every 10 turns

    def __init__(self):
        self.l2_summary = ""
        self.current_block: list[dict] = []
        self.turn_count = 0

    def add(self, role: str, content: str):
        self.current_block.append({"role": role, "content": content})
        self.turn_count += 1
        if len(self.current_block) >= self.L1_TRIGGER:
            l1 = summarise_block(self.current_block)
            self.l2_summary = (
                merge_summaries(self.l2_summary, l1) if self.l2_summary else l1
            )
            self.current_block = []

    def context_block(self) -> str:
        parts = []
        if self.l2_summary:
            parts.append(f"[Session history summary]\n{self.l2_summary}")
        if self.current_block:
            recent = "\n".join(f"{m['role'].upper()}: {m['content']}"
                                for m in self.current_block[-4:])
            parts.append(f"[Recent turns]\n{recent}")
        return "\n\n".join(parts)
